import React from "react";
import { useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();

  const isLoggedIn = localStorage.getItem("isLoggedIn") === "true";

  const handleLogout = () => {
    localStorage.removeItem("isLoggedIn");
    alert("Logged out");
    navigate("/login");
  };

  return (
    <header style={styles.navbar}>

      {/* Logo */}
      <div style={styles.logoContainer}>
        <h2 style={styles.logoText}>DocBook</h2>
      </div>

      <ul style={styles.navLinks}>

        {/* 🟡 NOT LOGGED IN */}
        {!isLoggedIn && (
          <>
            <li style={styles.link} onClick={() => navigate("/login")}>
              Login
            </li>

            <li style={styles.link} onClick={() => navigate("/")}>
              Register
            </li>
          </>
        )}

        {/* 🟢 LOGGED IN */}
        {isLoggedIn && (
          <>
            <li style={styles.link} onClick={() => navigate("/home")}>
              Home
            </li>

            <li style={styles.link}>
              Doctors
            </li>

            <li style={styles.logout} onClick={handleLogout}>
              Logout
            </li>
          </>
        )}

      </ul>
    </header>
  );
}

export default Navbar;

// Styles
const styles = {
  navbar: {
    backgroundColor: "#2c3e50",
    color: "white",
    padding: "15px 30px",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
  },

  logoContainer: {
    display: "flex",
    alignItems: "center",
    gap: "10px",
  },

  logoText: {
    margin: 0,
  },

  navLinks: {
    listStyle: "none",
    display: "flex",
    gap: "20px",
    margin: 0,
    padding: 0,
  },

  link: {
    cursor: "pointer",
  },

  logout: {
    color: "#e74c3c",
    fontWeight: "bold",
    cursor: "pointer",
  },
};
